def solution(limit: int = 28123) -> int:
    # Correctly compute sum of proper divisors for all n up to limit
    sum_divs = [0] * (limit + 1)
    for i in range(1, limit // 2 + 1):
        for j in range(2 * i, limit + 1, i):
            sum_divs[j] += i

    abundants = [i for i, s in enumerate(sum_divs) if s > i]

    is_abundant_sum = [False] * (limit + 1)
    for i in range(len(abundants)):
        for j in range(i, len(abundants)):
            s = abundants[i] + abundants[j]
            if s <= limit:
                is_abundant_sum[s] = True
            else:
                break

    return sum(i for i in range(1, limit + 1) if not is_abundant_sum[i])


